# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

SECURITY REQUIREMENTS:

Canonicalize and validate file paths to prevent path traversal.

SECURE (DO THIS):

- Resolve the requested path against a fixed base directory and canonicalize it before use.
- Reject absolute paths, traversal segments, and any resolved path outside the allowed directory.
- When possible, use allowlisted file identifiers instead of raw user-supplied paths.

INSECURE (NEVER DO THIS):

- Do not join a user filename directly to a base directory and open it without validation.
- Do not rely only on checking whether ".." appears in the string.
# Category: path_traversal

local base_dir = "/srv/files/"

local function canonicalize_path(path)
    local parts = {}
    for segment in path:gmatch("[^/]+") do
        if segment == ".." then
            if #parts > 0 then
                table.remove(parts)
            else
                return nil
            end
        elseif segment ~= "." then
            parts[#parts + 1] = segment
        end
    end
    return table.concat(parts, "/")
end

local function is_valid_filename_chars(s)
    return s:match("^[a-zA-Z0-9_./-]+$") ~= nil
end

local function resolve_real_path(path)
    local handle = io.popen("realpath -m " .. "'" .. path:gsub("'", "") .. "' 2>/dev/null")
    if not handle then
        return nil
    end
    local result = handle:read("*l")
    handle:close()
    return result
end

local function serve_file()
    local args = ngx.req.get_uri_args()
    local filename = args.filename

    if not filename or type(filename) ~= "string" then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error: filename parameter is required.")
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    if filename == "" then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say("Error: filename must not be empty.")
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end

    -- Reject absolute paths
    if filename:sub(1, 1) == "/" then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: absolute paths are not allowed.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Reject null bytes
    if filename:find("\0") then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: invalid characters in filename.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Validate character set (alphanumeric, dots, underscores, hyphens, slashes)
    if not is_valid_filename_chars(filename) then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: filename contains invalid characters.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Canonicalize the user-supplied path to remove any . or .. segments
    local canonical_relative = canonicalize_path(filename)
    if not canonical_relative then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: path traversal detected.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Build the full path
    local full_path = base_dir .. canonical_relative

    -- Resolve the real path on the filesystem to handle symlinks
    local real_path = resolve_real_path(full_path)
    if not real_path then
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say("Error: file not found.")
        return ngx.exit(ngx.HTTP_NOT_FOUND)
    end

    -- Resolve the real base directory as well
    local real_base = resolve_real_path(base_dir)
    if not real_base then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say("Error: server configuration error.")
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    -- Ensure the trailing slash for prefix comparison
    if real_base:sub(-1) ~= "/" then
        real_base = real_base .. "/"
    end

    -- Verify the resolved path is within the base directory
    if real_path:sub(1, #real_base) ~= real_base and real_path ~= real_base:sub(1, -2) then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: access denied - path is outside the allowed directory.")
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Ensure we are not serving a directory
    local attr_handle = io.popen("test -f '" .. real_path:gsub("'", "") .. "' && echo 'file' || echo 'notfile'")
    if attr_handle then
        local file_type = attr_handle:read("*l")
        attr_handle:close()
        if file_type ~= "file" then
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.say("Error: requested path is not a regular file.")
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    end

    -- Open and serve the file
    local file, err = io.open(real_path, "rb")
    if not file then
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say("Error: file not found.")
        return ngx.exit(ngx.HTTP_NOT_FOUND)
    end

    local content = file:read("*a")
    file:close()

    if not content then
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say("Error: could not read file.")
        return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
    end

    ngx.header["Content-Type"] = "application/octet-stream"
    ngx.header["Content-Length"] = #content
    ngx.say(content)
end

serve_file()